var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내가 어떤 놈인지 알면서도 이런 제안을 하다니, 별일이네.","JPN":"俺がどんな奴かは知ってるんだろ？なのにそんな提案をするなんて、変わった奴だ。","ENG":"You know what kind of man I am. Do you still want to keep me? You're strange.","TWN":"你知道我的為人還提出這種提議，真奇怪。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내가 의뢰인 당신이었다면 나 같은 놈과는 상종도 안 하려고 했을 거야.","JPN":"俺があんたの立場だったら、俺のような奴と関わりを持とうとはしない。","ENG":"If I were you, I'd stay as far away from me as I could.","TWN":"如果我是你，我絕對不會找像我這種人來委託事情的啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"나 같은 살인마를 믿고 정식으로 고용하겠다니. 이건 도박이나 다름없다고.","JPN":"殺人鬼に信頼を寄せ、正式に雇うなんて……正気の沙汰ではないからな。","ENG":"You're making a losing bet, hiring a murderer like me.","TWN":"你竟然正式雇傭我這種殺人魔，你這是在冒險。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭐, 그렇다고 그쪽과 함께 일하는 게 싫다는 뜻은 아니야.","JPN":"まあ、あんたと仕事をするのが嫌ってわけじゃないさ。","ENG":"Well, I'm not saying that I don't want to work for you.","TWN":"唔，我不是不想和你合作的意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"항상 범죄자를 죽이는 데만 혈안이 되어있다가, 간만에 사람 구하는 일을 해보니 조금은 속죄하는 기분도 들고 마음이 좀 가벼워지더라고.","JPN":"いつも血眼になって犯罪者を殺して回ってたからな。たまに人助けなんぞやると、少しは償えたような気がするし、心も幾分か軽くなる。","ENG":"You know, I had been crazy for killing those criminals. So saving people was a rather redeeming experience for me.","TWN":"原本只顧著制裁犯罪者的我，最近做了些可以救人的工作，感受到了一絲絲贖罪的心情，内心變平靜了不少。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"하하, 알고 있어. 나 같은 살인마가 속죄니 마음의 평안이니 지껄이는 건 뻔뻔하지.","JPN":"ハハ、わかってるさ。俺のような殺人鬼に、償いだの、心の安らぎだのを求める資格がないってことくらい。","ENG":"Hah hah, I know it's shameless for a bloody murderer like myself to talk about redemption.","TWN":"哈哈，我也知道。我這種殺人魔不該奢望贖罪或妄想心靈能得到安息。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"한때는 복수를 위해서라면 그 대가가 뭐라도 상관없을 줄 알았는데, 정작 내가 뭔가를 잃는 건 두렵더라고.","JPN":"かつては復讐のためにどんな代償も払うつもりでいた。だが、いざその時になると、自分が何かを失うことが恐ろしくなっちまったのさ。","ENG":"Once, I thought I could sacrifice anything for revenge. But I found myself being worried about losing mine.","TWN":"我曾以為，只要是為了報仇所付出的任何代價都是值得的，但當我發現自己將因此失去什麼的時候，才驚覺這一切是很可怕的事情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"이미 각오한 일이라고 해도...... 동료가 죽어가는 걸 담담하게 지켜볼 수 있을 리 없잖아.","JPN":"すでに覚悟を決めていたとはいえ……仲間達が死んでいくのを、穏やかな気持ちで見守れるわけがなかったんだ。","ENG":"Even if I was ready, I couldn't watch my fellows die before my eyes.","TWN":"雖說早已做好了覺悟……但有誰能淡定地看著自己的同伴死去呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그래서 한 번은 기도도 해봤어. 내게 동료들 모두를 지킬 수 있는 힘을 달라고 말이야.","JPN":"だからある時、俺は神に祈ったものさ。仲間をすべて守れるだけの力を与えてくれってな。","ENG":"I even prayed to God to give me the power to protect them.","TWN":"所以我祈禱過，祈禱賜予我力量以保護所有同伴。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아주 당연하게도, 그 소원은 물론 이뤄지지 않았지.","JPN":"もちろん、その祈りが聞き届けられることはなかった。","ENG":"Of course, my prayers weren't answered.","TWN":"顯然，願望没有實現。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"처음엔 그게 불공평하게 느껴졌어.","JPN":"はじめは理不尽としか思えなかった。","ENG":"At first, I thought that was unfair.","TWN":"一開始我覺得很不公平。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"하지만 당신을 만나고부터는 그게 서서히 이해가 되기 시작하더군.","JPN":"だが、あんたに会ってようやくわかったんだ。","ENG":"But I get it now that I met you.","TWN":"但遇到你之後，我漸漸明白了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"정말로 힘을 주는 신이 있다면, 그건 내가 아닌 당신 같은 사람에게 주어지는 게 마땅했던 거야.","JPN":"もし力を授ける神がいるとすれば、それは俺ではなく、あんたのような人間に味方するだろうとな。","ENG":"If there really was a God, he would give such power to someone like you instead of me.","TWN":"如果真的有神靈會賜予力量，那麼得到力量的人應該是你而不是我這種人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"난 그저 내가 원하는 것만이 이뤄지길 바라던 흔한 범죄자들 중 하나일 뿐이겠지만, 당신은 달라.","JPN":"俺は、自分の望みを叶えることしか頭にないような、世に溢れるただの犯罪者さ。だが、あんたは違う。","ENG":"I'm just one of many selfish criminals who want their wishes to come true. But you're different.","TWN":"我只是試圖夢想成真的眾多犯罪者中的一個，而你卻不一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그래서 다행이라고 생각해.","JPN":"そんなあんたに会えて良かった。","ENG":"And I'm glad that I met you.","TWN":"所以我很慶幸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"당신을 만나지 못했다면, 아마 끝끝내 이 불공평한 세상을 저주했을 테니까.","JPN":"もしあんたに会っていなければ、俺は最期の時まで、この理不尽な世界を呪っていただろうからな。","ENG":"I would have died cursing this unfair world if I didn't.","TWN":"如果没有遇見你，我一定會詛咒這個不公平的世界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내게 필요했던 건 힘 같은 게 아니야.","JPN":"今ならわかるさ。俺が本当に望んだものは力なんかじゃない。","ENG":"It turned out I didn't need power.","TWN":"我缺少的不是力量。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"이런 난장판인 세상에도 아직 희망이 있다는 걸 눈으로 확인하고 싶었던 거지.","JPN":"このデタラメな世界にもまだ希望はある。その事実をこの目で確かめたかったのさ。","ENG":"I needed to believe that there still was hope left in this chaotic world.","TWN":"我其實想看到的…是這個混亂的世界中仍存有一絲希望。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};